-- Vitec: 76 rows
INSERT INTO quotes.pricelist_revisions (supplier_id, scope_label, revision_label, filename, is_active, summary)
SELECT s.id, NULL, 'Master BoM seed — Jul 2026', 'Master BoM (1).xlsx', true,
       jsonb_build_object('added', 76, 'changed', 0, 'removed', 0, 'unchanged', 0, 'row_count', 76, 'source', 'bom-seed-p3')
  FROM quotes.suppliers s
 WHERE s.code = 'VITEC'
   AND NOT EXISTS (SELECT 1 FROM quotes.pricelist_revisions pr
                    WHERE pr.supplier_id = s.id AND COALESCE(pr.scope_label,'') = '' AND pr.is_active);
WITH rev AS (
  SELECT pr.id AS rid, pr.supplier_id AS sid
    FROM quotes.pricelist_revisions pr JOIN quotes.suppliers s ON s.id = pr.supplier_id
   WHERE s.code = 'VITEC' AND COALESCE(pr.scope_label,'') = ''
     AND pr.revision_label = 'Master BoM seed — Jul 2026' AND pr.is_active
)
